  buildGroupDecline,
  buildGroupUninvite,
  buildGroupDisband,
  buildGroupSetLeader,
  parsePartyCommandResult,
  parseGroupInvite,
  parseGroupSetLeader,
  parseGroupDecline,
  parseGroupList,
  parsePartyMemberStats,
} from "wow/protocol/group";
import { registerStubs } from "wow/protocol/stubs";
import { EntityStore, type Entity, type EntityEvent } from "wow/entity-store";
import {
  FriendStore,
  type FriendEntry,
  type FriendEvent,
} from "wow/friend-store";
import {
  parseContactList,
  parseFriendStatus,
  buildAddFriend,
  buildDelFriend,
  SocialFlag,
  FriendStatus,
  FriendResult,
} from "wow/protocol/social";
import { parseUpdateObject } from "wow/protocol/update-object";
