import type { Socket } from "bun";
import { inflateSync } from "node:zlib";
import { PacketReader, PacketWriter } from "wow/protocol/packet";
import { SRP, type SRPResult } from "wow/crypto/srp";
import { Arc4 } from "wow/crypto/arc4";
import {
  GameOpcode,
  ChatType,
  Language,
  AuthOpcode,
} from "wow/protocol/opcodes";
import {
  parseChatMessage,
  buildChatMessage,
  buildNameQuery,
  parseNameQueryResponse,
  parseChannelNotify,
  buildWhoRequest,
  parseWhoResponse,
  buildRandomRoll,
  parseRandomRoll,
  parseServerBroadcast,
  parseNotification,
  type ChatMessage as RawChatMessage,
  type WhoResult,
} from "wow/protocol/chat";
import {
  buildLogonChallenge,
  parseLogonChallengeResponse,
  buildLogonProof,
  parseLogonProofResponse,
  buildRealmListRequest,
  parseRealmList,
  parseReconnectChallengeResponse,
  buildReconnectProof,
} from "wow/protocol/auth";
import {
  buildWorldAuthPacket,
  parseCharacterList,
  OpcodeDispatch,
  AccumulatorBuffer,
  INCOMING_HEADER_SIZE,
  buildOutgoingPacket,
  decryptIncomingHeader,
} from "wow/protocol/world";
import {
  buildGroupInvite,
  buildGroupAccept,
  buildGroupDecline,
  buildGroupUninvite,
  buildGroupDisband,
  buildGroupSetLeader,
  parsePartyCommandResult,
  parseGroupInvite,
  parseGroupSetLeader,
  parseGroupDecline,
  parseGroupList,
  parsePartyMemberStats,
} from "wow/protocol/group";
